class Solution {
public:
    string convert(string s, int numRows) {
        if (numRows == 1) return s;
        vector<string> rows(numRows);
        int r = 0, d = 1;
        for (char c : s) {
            rows[r] += c;
            if (r == 0) d = 1; else if (r == numRows - 1) d = -1;
            r += d;
        }
        string out;
        for (auto& row : rows) out += row;
        return out;
    }
};
